import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { Unit } from '../../core/models';

@Component({
  selector: 'app-unit-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, CentsPipe],
  templateUrl: './unit-form.component.html',
  styleUrl: './unit-form.component.css',
})
export class UnitFormComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal('');

  /** Canonical mock units, keyed by id for edit prefill. */
  readonly units = signal<Unit[]>([
    { id: 'u1', number: '101', bedrooms: 1, rentCents: 120000 },
    { id: 'u2', number: '102', bedrooms: 2, rentCents: 180000 },
    { id: 'u3', number: '201', bedrooms: 2, rentCents: 190000 },
    { id: 'u4', number: '202', bedrooms: 3, rentCents: 240000 },
  ]);

  /** Id of the unit being edited (null in create mode). */
  readonly editId = signal<string | null>(null);
  readonly isEdit = computed(() => this.editId() !== null);

  readonly form = this.fb.group({
    number: ['', [Validators.required]],
    bedrooms: [1, [Validators.required, Validators.min(0)]],
    rentDollars: [0, [Validators.required, Validators.min(0)]],
  });

  /** Live preview cents derived from the dollars input. */
  readonly previewCents = signal(0);

  constructor(
    private fb: FormBuilder,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      const existing = this.units().find((u) => u.id === id);
      if (!existing) {
        this.error.set('Unit not found.');
        return;
      }
      this.editId.set(id);
      this.form.patchValue({
        number: existing.number,
        bedrooms: existing.bedrooms,
        rentDollars: existing.rentCents / 100,
      });
    }
    this.previewCents.set(Math.round((this.form.controls.rentDollars.value ?? 0) * 100));
    this.form.controls.rentDollars.valueChanges.subscribe((v) => {
      this.previewCents.set(Math.round((Number(v) || 0) * 100));
    });
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const raw = this.form.getRawValue();
    const payload = {
      id: this.editId() ?? undefined,
      number: raw.number,
      bedrooms: Number(raw.bedrooms),
      rentCents: Math.round((Number(raw.rentDollars) || 0) * 100),
    };
    this.loading.set(true);
    // Mock persistence — no real API in the portal mockup.
    console.log(this.isEdit() ? 'Update unit' : 'Create unit', payload);
    setTimeout(() => {
      this.loading.set(false);
      this.router.navigate(['/units']);
    }, 450);
  }
}
